import { buildApplication, buildRouteMap } from "@stricli/core";
import { disableCommand } from "./commands/disable.js";
import { enableCommand } from "./commands/enable.js";
import { hooksRouteMap } from "./commands/hooks/index.js";
import { loginCommand } from "./commands/login.js";
import { logoutCommand } from "./commands/logout.js";
import { uploadCommand } from "./commands/upload.js";
import { whoamiCommand } from "./commands/whoami.js";

const routes = buildRouteMap({
	routes: {
		login: loginCommand,
		logout: logoutCommand,
		whoami: whoamiCommand,
		upload: uploadCommand,
		enable: enableCommand,
		disable: disableCommand,
		hooks: hooksRouteMap,
	},
	docs: {
		brief: "CLI tools for managing Claude Code sessions",
		hideRoute: { hooks: true },
	},
});

export const app = buildApplication(routes, {
	name: "rudel",
	versionInfo: {
		currentVersion: "0.1.4",
	},
	scanner: {
		caseStyle: "allow-kebab-for-camel",
	},
});

{
	"name": "rudel",
	"version": "0.1.4",
	"type": "module",
	"description": "CLI for the Coding Agent Analytics Platform rudel.ai",
	"homepage": "https://app.rudel.ai",
	"bin": {
		"rudel": "./dist/cli.js"
	},
	"files": [
		"dist",
		"README.md"
	],
	"scripts": {
		"dev": "bun run src/bin/cli.ts",
		"check-types": "tsc --noEmit",
		"build": "bun build src/bin/cli.ts --outdir dist --target bun",
		"test": "bun test"
	},
	"dependencies": {
		"@orpc/client": "^1.13.5",
		"@orpc/contract": "^1.13.5",
		"@stricli/core": "^1.2.5"
	},
	"devDependencies": {
		"@rudel/api-routes": "workspace:*",
		"@rudel/typescript-config": "workspace:*",
		"bun-types": "latest",
		"typescript": "5.9.2"
	}
}

